class LoginAttemptService {
    private static final int MAX_FAILED = 5;
    private final Map<String, Integer> failedByUser = new ConcurrentHashMap<>();
    private final Map<String, Instant> lockUntil = new ConcurrentHashMap<>();

    boolean isLocked(String username) {
        Instant until = lockUntil.get(username);
        return until != null && until.isAfter(Instant.now());
    }

    void onFailure(String username) {
        int failed = failedByUser.merge(username, 1, Integer::sum);
        if (failed >= MAX_FAILED) {
            lockUntil.put(username, Instant.now().plus(10, ChronoUnit.MINUTES));
        }
    }

    void onSuccess(String username) {
        failedByUser.remove(username);
        lockUntil.remove(username);
    }
}

